**Definir a structura do AIEOS**

Aqui vai uma estrutura básica do AIEOS em C#:
```csharp
public class Program
{
    public static void Main(string[] args)
    {
        // Definindo a structura do AIEOS
        public struct AIEOS
        {
            public string Nome;
            public string Descrição;
            public int Version;
            public DateTime DataCriação;

            public AIEOS(string nome, string descrição, int versão, DateTime dataCriação)
            {
                Nome = nome;
                Descrição = descrição;
                Version = versão;
                DataCriação = dataCriação;
            }

            public override string ToString()
            {
                return $"Nome: {Nome}\nDescrição: {Descrição}\nVersão: {Version}\nData Criação: {DataCriação}";
            }
        }

        // Criando um objeto AIEOS
        AIEOS aieos = new AIEOS("AIEOS", "Descrição do AIEOS", 1, new DateTime(2022, 1, 1));

        // Imprime a structura do AIEOS
        Console.WriteLine(aieos.ToString());
    }
}
```
